# IMPORTANT: Make sure the data length matches our x_data if len(data_int) == CHUNK: self.line.set_ydata(data_int)
return self.line,
def start(self): self.ani = FuncAnimation(self.fig, self.update, blit=True, interval=0) plt.show()
