def get_signal(chunk_size): """ Generates quantum noise modulated by Einstein's mass-energy equivalence. The signal intensity waves based on a simulated fluctuating mass. """ # 1. Generate raw quantum noise using MicroQiskit # We take enough shots to fill the chunk res = simulate(_qc, shots=chunk_size, get='memory') raw_noise = np.array([int(bit, 2) for bit in res])
# Center the noise (change 0/1 to -1/1) and scale it raw_noise = (raw_noise * 2 - 1) * 15000
# 2. Einstein modulation logic (E = mc^2) # Slow time axis for modulation t = np.linspace(0, 1, chunk_size) c = 3e8 # Speed of light constant
